export default {
	data() {
		return {
			InputBottom: 0,
			code: '',
			orderList: [],
			keyword: '',
			tid: '',
			type: '',
			projetcText: 'е…ЁйғЁйЎ№зӣ®',
			statusText: 'жҲҝжәҗзұ»еһӢ',
			typeText: 'жҲҗдәӨзұ»еһӢ',
			modalName: '',
			contents: '',
			p_id: '',
			per_page: 0, //дёҖйЎөеӨҡе°‘жқЎж•°жҚ®пјӣ
			current_page: 1, //еҪ“еүҚйЎөж•°пјӣ
			last_page: 0 ,//дёҖе…ұеӨҡе°‘йЎөпјӣ
			moreData: 'еҠ иҪҪжӣҙеӨҡж•°жҚ®...',
			total:0,
			page:0,
			dealProject:[{p_name:'е…ЁйғЁйЎ№зӣ®',p_id:'-1'}],//е·ІеӨ„зҗҶйЎ№зӣ®
			p_index:0
		};
	},

	onLoad() {
		this.p_id = this.$store.state.project_id;
		this.getOrderList();
		this.getDealProject();
	},
	onReachBottom() {
		if (this.current_page < this.last_page) {
			this.current_page = this.current_page + 1;
			this.page = this.current_page;
			this.getOrderList();
		}
	},
	methods: {
		getDealProject(){
			this.$api.Getdealprojectbookingapi({},res =>{
				this.dealProject = [{p_name:'е…ЁйғЁйЎ№зӣ®',p_id:'-1'}];
				res.data.forEach(res =>{
					this.dealProject.push(res)
				})
			})
		},
		
		cName(names) {
			if (names.length > 2) {
				return names.substring(0, 2);
			} else {
				return names;
			}
		},
		stop() {},
		order() {
			let _this = this;
			let items = ['жҲҗдәӨзұ»еһӢ', 'жҺ’еҸ·', 'и®Өиҙӯ'];
			uni.showActionSheet({
				itemList: items,
				success: function(res) {
					_this.typeText = items[res.tapIndex];
					if (res.tapIndex == 0) {
						_this.type = '';
					}
					if (res.tapIndex != 0) {
						_this.type = res.tapIndex;
					}
					_this.orderList = [];
					_this.page = 1;
					_this.getOrderList();
				}
			});
		},
		detail(item) {
			uni.navigateTo({
				url: '/pages/order/traded_order_detail?id=' + item.id+'&type='+item.type
			});
		},
		changeProject(e) {
			this.p_index = e.detail.value;
			if(this.dealProject[this.p_index].p_id != -1){
				this.p_id = this.dealProject[this.p_index].p_id;
				this.page = 1;
				this.getOrderList();
			}
		},
		clickStatus() {
			let _this = this;
			let items = ['жҲҝжәҗзұ»еһӢ', 'дҪҸе®…', 'е•Ҷдёҡ', 'еҲ«еў…', 'иҪҰдҪҚ']; //1-дҪҸе®…пјҢ2-е•ҶдёҡпјҢ3-еҲ«еў…пјҢ4-иҪҰдҪҚ
			uni.showActionSheet({
				itemList: items,
				success: function(res) {
					_this.statusText = items[res.tapIndex];
					if (res.tapIndex == 0) {
						_this.tid = '';
					} else {
						_this.tid = res.tapIndex;
					}
					_this.page = 1;
					_this.orderList = [];
					_this.getOrderList();
				}
			});
		},
		cancel(item) {
			let _this = this;
			uni.showModal({
				title: 'еҸ–ж¶Ҳи®ўеҚ•',
				content: 'жҳҜеҗҰеҸ–ж¶Ҳи®ўеҚ•пјҹ',
				success(res) {
					if (res.confirm) {
						_this.$api.SalesProjectCancelorder({ order_id: item.cbo_id }, res => {
							_this.getOrderList();
						});
					}
				}
			});
		},
		search(){
			this.orderList = [];
			this.getOrderList();
		},
		getOrderList() {
			let data = {
				pid: this.p_id, //жҳҜ	int	йЎ№зӣ®id
				type: this.type, //	жҳҜ	int	и®ўеҚ•зұ»еһӢпјҲ1-жҺ’еҸ·пјҢ2-и®ӨиҙӯпјҢ3-жҺ’еҸ·иЎҘж¬ҫпјҢ4-иҙӯжҲҝж¬ҫиЎҘж¬ҫпјү
				keyword: this.keyword, //	жҳҜ	string	и®ўеҚ•еҸ·гҖҒе®ўжҲ·еҗҚз§°гҖҒиҒ”зі»з”өиҜқе…ій”®еӯ—жҹҘиҜў
				tid: this.tid ,// жҲҗдәӨзұ»еһӢ1-дҪҸе®…пјҢ2-е•ҶдёҡпјҢ3-еҲ«еў…пјҢ4-иҪҰдҪҚ
				page:this.page
			};
			uni.showLoading({
				title: 'жӯЈеңЁиҺ·еҸ–ж•°жҚ®...'
			});
			this.$api.Getdeallistbookingapi(data, res => {
				res.data.data.forEach(resp => {
					this.orderList.push(resp);
				});
				this.per_page = res.data.per_page; //дёҖйЎөеӨҡе°‘жқЎж•°жҚ®пјӣ
				this.current_page = res.data.current_page; //еҪ“еүҚйЎөж•°пјӣ
				this.last_page = res.data.last_page; //дёҖе…ұеӨҡе°‘йЎөпјӣ
				this.total = res.data.total; //жҖ»жқЎж•°
			});
		},
		InputFocus(e) {
			this.InputBottom = e.detail.height;
		},
		InputBlur(e) {
			this.InputBottom = 0;
		}
	}
};
